def normalize_legacy_filename(filename):
    """
    Handle backward compatibility with older file naming conventions.
    Legacy systems may have used spaces, uppercase, or special characters
    in filenames that modern systems have since normalized.
    """
    # Strip leading/trailing whitespace
    filename = filename.strip()

    # Legacy convention: spaces were sometimes encoded as underscores
    # Support both conventions
    filename = filename.replace(' ', '_')

    # Legacy convention: some old systems used uppercase extensions
    name, ext = os.path.splitext(filename)
    ext = ext.lower()
    filename = name + ext

    # Remove any characters that aren't alphanumeric, underscores, hyphens, or dots
    # This also strips out path separators and other dangerous characters
    filename = re.sub(r'[^\w\-.]', '', filename)

    # Prevent hidden files (starting with dot)
    filename = filename.lstrip('.')

    # Collapse multiple dots to a single dot (prevent tricks like "file....txt")
    filename = re.sub(r'\.{2,}', '.', filename)

    return filename


def validate_and_resolve_path(filename):
    """
    Validate the filename and resolve the full path, ensuring it stays
    within the UPLOAD_DIRECTORY. Returns the resolved path or None if invalid.
    """
    if not filename:
        return None

    # Normalize legacy filename conventions
